/// Direction enum for [BTScrollbar].
enum BTScrollbarDirection {
  /// Vertical scroll axis.
  vertical,

  /// Horizontal scroll axis.
  horizontal,
}

import 'package:btech_tokens/btech_tokens.dart';
import 'package:flutter/material.dart';

/// BTScrollbar — token-styled scrollbar wrapper atom (Figma 2037:4).
///
/// Wraps [RawScrollbar] with btech design tokens:
/// - Thumb: [btColor.bg.subtlest] (neutral-300)
/// - Track: [btColor.bg.subtle] (neutral-50)
/// - Track border: [btColor.bg.primary]
/// - Thickness: 5dp, radius: 8dp
///
/// Example:
/// ```dart
/// BTScrollbar(
///   child: ListView.builder(
///     itemCount: 100,
///     itemBuilder: (_, i) => ListTile(title: Text('Item $i')),
///   ),
/// )
///
/// // With explicit controller
/// BTScrollbar(
///   controller: _scrollController,
///   thumbVisibility: true,
///   child: SingleChildScrollView(
///     controller: _scrollController,
///     child: MyLongContent(),
///   ),
/// )
/// ```
class BTScrollbar extends StatelessWidget {
  const BTScrollbar({
    required this.child,
    this.controller,
    this.thumbVisibility = true,
    this.interactive = true,
    this.padding,
    super.key,
  });

  /// The widget that will be scrolled.
  final Widget child;

  /// Optional [ScrollController] to attach to the scrollbar.
  final ScrollController? controller;

  /// When true (default), the thumb is always visible.
  /// When false, the thumb fades in only while scrolling.
  final bool thumbVisibility;

  /// When true (default), the user can drag the thumb to scroll.
  final bool interactive;

  /// Padding around the scrollbar thumb. Defaults to none.
  final EdgeInsets? padding;

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;

    return RawScrollbar(
      controller: controller,
      thumbColor: colors.bg.subtlest,
      trackColor: colors.bg.subtle,
      trackBorderColor: colors.bg.primary,
      thickness: 5,
      radius: const Radius.circular(8),
      thumbVisibility: thumbVisibility,
      trackVisibility: true,
      interactive: interactive,
      padding: padding,
      child: child,
    );
  }
}
